export const code = async (inputs) => {
  const regions = (typeof inputs.regions_array === 'string' 
    ? JSON.parse(inputs.regions_array) 
    : inputs.regions_array) as any[];

  const subscriptions = (typeof inputs.subscriptions_array === 'string' 
    ? JSON.parse(inputs.subscriptions_array) 
    : inputs.subscriptions_array) as any[];

  return { regions, subscriptions };
};

export const code = async (inputs) => {
  return inputs.subscriptions && inputs.subscriptions.length > 3;
};

export const code = async (inputs) => {
  const prices = inputs.lastDaysPrices;

  if (!prices || prices.length === 0) {
    return { average: 0, currency: null };
  }

  const total = prices.reduce((sum, [price]) => sum + price, 0);
  const average = total / prices.length;

  return {
    average,
  };
};

export const code = async (inputs) => {
  const rawItems = Array.isArray(inputs.items) ? inputs.items : [];

  const ids = rawItems
    .map((item) => {
      if (!item) return null;

      if (typeof item === "string") {
        try {
          return JSON.parse(item)?.id || null;
        } catch {
          return null;
        }
      }

      if (typeof item === "object") {
        return item.id || null;
      }

      return null;
    })
    .filter(Boolean);

  return ids.map((id) => `"${id}"`).join(", ");
};

export const code = async (inputs) => {
  const costs = Array.isArray(inputs.costs) ? inputs.costs : [];
  const items = Array.isArray(inputs.items) ? inputs.items : [];

  const normalizeId = (value) => String(value || "").toLowerCase();

  const regionByResourceId = {};

  for (const rawItem of items) {
    if (!rawItem) continue;

    let item = rawItem;

    if (typeof rawItem === "string") {
      try {
        item = JSON.parse(rawItem);
      } catch {
        continue;
      }
    }

    if (!item || typeof item !== "object" || !item.id) continue;

    regionByResourceId[normalizeId(item.id)] =
      item.region ||
      item.location ||
      item.properties?.geoRegion ||
      null;
  }

  const grouped = {};

  for (const [cost, date, resourceId, currency] of costs) {
    const normalizedResourceId = normalizeId(resourceId);

    if (!grouped[normalizedResourceId]) {
      grouped[normalizedResourceId] = {
        resourceId,
        currency,
        region: regionByResourceId[normalizedResourceId] || null,
        datesWithCosts: []
      };
    }

    grouped[normalizedResourceId].datesWithCosts.push([cost, date]);
  }

  return Object.values(grouped);
};

export const code = async (inputs) => {
  const items = inputs.pricingItems || [];

  const today = new Date();
  const dateKey = Number(
    `${today.getUTCFullYear()}${String(today.getUTCMonth() + 1).padStart(2, "0")}${String(today.getUTCDate()).padStart(2, "0")}`
  );

  return items
    .map(item => {
      const parsedItem = typeof item === "string" ? JSON.parse(item) : item;

      return {
        region: parsedItem.location,
        resourceId: parsedItem.resourceId,
        currency: parsedItem.currency || "USD",
        datesWithCosts: [
          [
            parsedItem.dailyPricing || 0,
            dateKey
          ]
        ]
      };
    })
    .filter(item => item.resourceId);
};

export const code = async (inputs) => {
  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/\s+/g, "")
      .trim();

  const parseItem = (item) => {
    if (typeof item !== "string") return item;

    try {
      return JSON.parse(item);
    } catch {
      return null;
    }
  };

  const items = Array.isArray(inputs?.items)
    ? inputs.items
    : inputs?.items
      ? [inputs.items]
      : [];

  const region =
    inputs?.region?.serverValue ??
    inputs?.region?.value ??
    inputs?.region;

  const normalizedRegion = normalize(region);

  return items
    .map(parseItem)
    .filter(Boolean)
    .filter((item) => normalize(item?.location) === normalizedRegion);
};

export const code = async (inputs) => {
  const seriesArr =
    inputs?.avgCpuMetrics?.timeseries ?? inputs?.avgCpuMetrics;
  if (!Array.isArray(seriesArr)) return 0;

   return seriesArr.reduce((globalMax, { data }) => {
    if (!Array.isArray(data)) return globalMax;

    const localMax = data.reduce((m, { average }) =>
      typeof average === 'number' && average > m ? average : m
    , 0);

    return localMax > globalMax ? localMax : globalMax;
  }, 0);
};

export const code = async (inputs) => {
  const seriesArr =
    inputs?.maxCpuMetrics?.timeseries ?? inputs?.maxCpuMetrics;
  if (!Array.isArray(seriesArr)) return 0;

  return seriesArr.reduce((max, series) => {
    if (!Array.isArray(series?.data)) return max;

    const seriesMax = series.data.reduce((m, p) => {
      return typeof p?.maximum === "number" && p.maximum > m ? p.maximum : m;
    }, 0);

    return seriesMax > max ? seriesMax : max;
  }, 0);
};

export const code = async (inputs) => {
  const metrics = inputs?.metrics;

  const toMetricArr = (value) => {
    if (!value) return [];

    if (typeof value === "string") {
      try {
        return toMetricArr(JSON.parse(value));
      } catch {
        return [];
      }
    }

    if (Array.isArray(value)) return value.flatMap(toMetricArr);

    if (Array.isArray(value.value)) return value.value.flatMap(toMetricArr);

    if (Array.isArray(value.timeseries)) return [value];

    return [];
  };

  const normalize = (value) =>
    String(value || "")
      .toLowerCase()
      .replace(/\s+/g, "")
      .trim();

  const allMetrics = toMetricArr(metrics);

  const networkMetrics = allMetrics.filter((metric) => {
    const metricName = normalize(
      metric?.name?.value ||
        metric?.name?.localizedValue ||
        metric?.id ||
        ""
    );

    return (
      metricName.includes("networkintotal") ||
      metricName.includes("networkouttotal")
    );
  });

  const buckets = new Map();

  for (const metric of networkMetrics) {
    const timeseries = Array.isArray(metric?.timeseries)
      ? metric.timeseries
      : [];

    for (const series of timeseries) {
      const data = Array.isArray(series?.data) ? series.data : [];

      for (const point of data) {
        const timeStamp = point?.timeStamp;
        const average = point?.average;

        if (!timeStamp || typeof average !== "number") continue;

        buckets.set(timeStamp, (buckets.get(timeStamp) || 0) + average);
      }
    }
  }

  let maxBytesPerSecond = 0;

  for (const value of buckets.values()) {
    if (value > maxBytesPerSecond) {
      maxBytesPerSecond = value;
    }
  }

  return {
    networkTotal: (maxBytesPerSecond * 3600) / (1024 * 1024),
  };
};

